        return internal_imports

    # Find all .go files in the package (excluding _test.go)
    for file in os.listdir(pkg_full_path):
        if file.endswith(".go") and not file.endswith("_test.go") and not file.endswith(".pb.go"):
            file_path = os.path.join(pkg_full_path, file)
            imports = extract_imports_from_file(file_path)
            for imp in imports:
                if MODULE_PREFIX in imp:
                    # Convert to relative path
                    if imp.startswith(MODULE_PREFIX + "/"):
                        rel = imp[len(MODULE_PREFIX) + 1:]
                        rel = normalize_path(rel)
                        internal_imports.add(rel)
                    elif imp == MODULE_PREFIX:
                        # Root package, though unlikely
                        pass

    return internal_imports

# BFS to discover all packages
visited = set()
queue = deque([START_PKG])
graph = defaultdict(set)  # pkg -> set of packages that pkg imports

while queue:
    pkg = queue.popleft()
    if pkg in visited:
        continue

    visited.add(pkg)
    imports = get_internal_imports(pkg)

    for imp in imports:
        graph[pkg].add(imp)
        if imp not in visited:
            queue.append(imp)

print("Dependency Graph:")
print("-" * 80)
for pkg in sorted(visited):
    if graph[pkg]:
        deps = ", ".join(sorted(graph[pkg]))
        print(f"{pkg}")
        print(f"  → {deps}")
    else:
        print(f"{pkg} (leaf)")

print("\n\nAll packages discovered:")
print("-" * 80)
for pkg in sorted(visited):
    print(f"  {pkg}")

# Now do topological sort
print("\n\nTopological Sort (Kahn's algorithm):")
print("-" * 80)

# Build in-degree map
in_degree = {pkg: 0 for pkg in visited}
edges = defaultdict(set)  # pkg -> packages that depend on pkg

for pkg, deps in graph.items():
    for dep in deps:
        if dep in visited:
            in_degree[pkg] += 1
            edges[dep].add(pkg)

# Queue of packages with no dependencies
queue = deque([pkg for pkg in visited if in_degree[pkg] == 0])
sorted_order = []

while queue:
    pkg = queue.popleft()
    sorted_order.append(pkg)

    for dependent in sorted(edges[pkg]):  # Sort for consistent output
        in_degree[dependent] -= 1
        if in_degree[dependent] == 0:
            queue.append(dependent)

if len(sorted_order) != len(visited):
    print("ERROR: Cycle detected in dependency graph!")
    print(f"Only sorted {len(sorted_order)} out of {len(visited)} packages")
    print("Remaining packages with cycles:")
    for pkg in visited:
        if pkg not in sorted_order:
            print(f"  {pkg}")
else:
    print("Result:")
    for pkg in sorted_order:
        print(f"  {pkg}")

    print("\n\nJSON format:")
    import json
    print(json.dumps(sorted_order, indent=2))

